import{_ as e,o,c as r,a2 as p}from"./chunks/framework.Cr-Z7ngm.js";const b=JSON.parse('{"title":"如何下载长桥App","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/download-app.md","filePath":"zh-CN/account/download-app.md"}'),t={name:"account/download-app.md"};function l(i,a,n,d,s,h){return o(),r("div",null,[...a[0]||(a[0]=[p('<h1 id="如何下载长桥app" tabindex="-1">如何下载长桥App <a class="header-anchor" href="#如何下载长桥app" aria-label="Permalink to &quot;如何下载长桥App&quot;">​</a></h1><blockquote><p>以下下载链接的版本不一定是最新版本，安装后可在 App 内自行检查更新。</p></blockquote><h2 id="安卓" tabindex="-1">安卓 <a class="header-anchor" href="#安卓" aria-label="Permalink to &quot;安卓&quot;">​</a></h2><p><a href="https://static.lbkrs.com/app/longbridge-online-release.apk" target="_blank" rel="noreferrer">下载链接</a></p><h2 id="苹果-ios" tabindex="-1">苹果（iOS） <a class="header-anchor" href="#苹果-ios" aria-label="Permalink to &quot;苹果（iOS）&quot;">​</a></h2><p>可通过 App Store 更新/安装长桥 App，包括自动更新、手动更新/安装两种方式。</p><blockquote><p><strong>中国大陆用户注意</strong>：若长桥 App 在中国大陆 App Store 无法搜索到，请使用下方「手动更新/安装」通过【已购项目】操作，无需切换 Apple ID 区域。</p></blockquote><h3 id="方式-1-自动更新" tabindex="-1">方式 1：自动更新 <a class="header-anchor" href="#方式-1-自动更新" aria-label="Permalink to &quot;方式 1：自动更新&quot;">​</a></h3><p>打开【设置】-【App Store】-【App 更新】，打开其中的【App 更新】开关，即可实现长桥 App 的自动更新。</p><p>注意：</p><ol><li>该方式下，您手机上的所有 App 均为自动更新；</li><li>若您误删了长桥 App，请参考下面的「方式 2：手动更新/安装」进行安装。</li></ol><h3 id="方式-2-手动更新-安装" tabindex="-1">方式 2：手动更新/安装 <a class="header-anchor" href="#方式-2-手动更新-安装" aria-label="Permalink to &quot;方式 2：手动更新/安装&quot;">​</a></h3><p>打开【App Store】，点击右上角头像进入【账户】页面，<strong>先在【账户】页面下拉刷新</strong>（若不刷新，可能后面步骤中看不到【更新】按钮，因此请务必下拉刷新），再点击进入【App】（较新 iOS 版本）或【已购项目】（较旧 iOS 版本），在【全部】中搜索&quot;长桥&quot;，找到长桥 App。</p><ol><li>若长桥 App 有更新，则可以看到【更新】按钮，点击即可更新；</li><li>若误删了长桥 App，则可以看到【下载】按钮，点击可下载安装；</li><li>若找不到长桥 App，请参考下面的「常见问题」。</li></ol><h3 id="常见问题-在【app】-【已购项目】中找不到长桥" tabindex="-1">常见问题：在【App】/【已购项目】中找不到长桥 <a class="header-anchor" href="#常见问题-在【app】-【已购项目】中找不到长桥" aria-label="Permalink to &quot;常见问题：在【App】/【已购项目】中找不到长桥&quot;">​</a></h3><p>可能原因及解决方法如下：</p><ol><li><strong>App 被隐藏</strong>：打开【App Store】→ 右上角头像 → 账户 → 顶部账户名 → 【账户设置】→ 【隐藏的已购项目】，找到&quot;长桥&quot;后点击【解除隐藏】，再按方式 2 操作；</li><li><strong>Apple ID 不匹配</strong>：当前登录的 Apple ID 不是当初下载长桥时使用的账号。打开【设置】→ 顶部账户名 → 拉到底部【退出登录】，换回之前的 Apple ID 重新登录，再按方式 2 操作。</li></ol><h2 id="mac" tabindex="-1">Mac <a class="header-anchor" href="#mac" aria-label="Permalink to &quot;Mac&quot;">​</a></h2><p><a href="https://download.wbrks.com/longbridge-desktop/prod/longbridge-pro-2.33.3-mac-x64.dmg" target="_blank" rel="noreferrer">x64 版本</a><br><a href="https://download.wbrks.com/longbridge-desktop/prod/longbridge-pro-2.33.3-mac-arm64.dmg" target="_blank" rel="noreferrer">M 芯片版本</a></p><h2 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h2><p><a href="https://download.wbrks.com/longbridge-desktop/prod/longbridge-pro-2.33.3-win-ia32.exe" target="_blank" rel="noreferrer">32 位系统</a><br><a href="https://download.wbrks.com/longbridge-desktop/prod/longbridge-pro-2.33.3-win-x64.exe" target="_blank" rel="noreferrer">64 位系统</a></p><h2 id="中国大陆存量用户说明" tabindex="-1">中国大陆存量用户说明 <a class="header-anchor" href="#中国大陆存量用户说明" aria-label="Permalink to &quot;中国大陆存量用户说明&quot;">​</a></h2><p>长桥已停止接受中国大陆境内用户通过存量证明方式开户。中国大陆境内已有账户的存量用户可继续正常使用长桥客户端进行投资交易，相关服务不受影响。</p><p>访问长桥官网时可能遇到卡顿或受限，建议直接通过 App 使用。如需客服支持，可通过 App 内【我的】-【帮助与客服】联系，或致电 +852 3851 1777。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/account/登录注册">登录注册</a> — 账户登录与注册流程</li><li><a href="/account/我的">我的</a> — App 我的页面功能说明</li></ul>',26)])])}const u=e(t,[["render",l]]);export{b as __pageData,u as default};
